120	export const runScenario = (scenario: Scenario): ScenarioResult => {
121	  let quoteCount = 0;
122	  const policyItems: Item[][] = [];
123	  const results = scenario.steps.map((step) => {
124	    if (step.op === "quote") {
125	      const premium = quotePremium(step.items, scenario.customer, quoteCount);
126	      quoteCount += 1;
127	      policyItems.push(step.items);
128	      return { premium };
129	    }
130	    const items = policyItems[step.policy];
131	    const cap = insuranceSum(items) * CAP_MULTIPLIER;
132	    const payout = step.incident.damages.reduce(
133	      (sum, damage) => sum + payoutForDamage(damage.amount),
134	      0,
135	    );
136	    return { payout, remainingCap: cap - payout };
137	  });
138	  return { results };
139	};
